import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()
        
        config_dict = {}
        
        for elem in root:
            if 'setting' not in elem.tag:
                continue
            
            setting_name = elem.attrib['name']
            setting_value = elem.text
            
            config_dict[setting_name] = setting_value
        
        return config_dict
    
    except ET.ParseError as e:
        print(f"Error parsing XML: {e}")
        return {}
    
    except FileNotFoundError:
        print("File not found")
        return {}